#!/bin/bash
set -e
echo "📥 Import Babelio en arrière-plan..."
cd "$(git rev-parse --show-toplevel)"
mkdir -p src/app/api/import src/app/api/import-status src/components/import src/app/import
python3 << 'PYEOF'
import base64
import os; os.makedirs("src/app/api/import", exist_ok=True)
open("src/app/api/import/route.ts", "wb").write(base64.b64decode(""))
import os; os.makedirs("src/app/api/import-status", exist_ok=True)
open("src/app/api/import-status/route.ts", "wb").write(base64.b64decode(""))
import os; os.makedirs("src/components/import", exist_ok=True)
open("src/components/import/ImportBanner.tsx", "wb").write(base64.b64decode(""))
import os; os.makedirs("src/app/import", exist_ok=True)
open("src/app/import/page.tsx", "wb").write(base64.b64decode(""))
import os; os.makedirs("src/app", exist_ok=True)
open("src/app/providers.tsx", "wb").write(base64.b64decode(""))
print("Files written OK")
PYEOF
git add -A
git commit -m "feat: async Babelio import with background progress banner"
git push
echo "🎉 Déployé !"